def get_band_text(band_key, language="RU", text_type="short"):
    item = SCORE_BAND_TEXTS.get(band_key, SCORE_BAND_TEXTS["not_calculated"])
    suffix = "ru" if language == "RU" else "en"
    return item.get(f"{text_type}_{suffix}", item.get(f"short_{suffix}", ""))
